// Extract the incoming WhatsApp message
const data = $input.first().json;

const messageObj = data.messages?.[0];
if (!messageObj || messageObj.type !== 'text') {
  // Ignore non-text messages (images, voice, etc.)
  return [];
}

const userMessage = messageObj.text?.body?.trim() || '';
const senderPhone = messageObj.from || '';

if (!userMessage) return [];

return [{ json: { userMessage, senderPhone } }];

// Aggregate all Airtable lead records + build the AI prompt
const allItems = $input.all();
const leads = allItems.map(item => item.json.fields || item.json);

const userMessage = $('Extract Message').first().json.userMessage;
const senderPhone = $('Extract Message').first().json.senderPhone;

// ── Compute summary stats ──────────────────────────────────────
const total = leads.length;

const byStatus = {};
leads.forEach(l => {
  const s = l['Lead Status'] || 'Unknown';
  byStatus[s] = (byStatus[s] || 0) + 1;
});

const totalRevenue = leads
  .filter(l => l['Lead Status'] === 'Job Done')
  .reduce((sum, l) => sum + (parseFloat(l['Final Invoice Amount']) || parseFloat(l['Quote Amount']) || 0), 0);

const totalQuoted = leads
  .filter(l => ['Quote Sent', 'Booked', 'Job Done'].includes(l['Lead Status']))
  .reduce((sum, l) => sum + (parseFloat(l['Quote Amount']) || 0), 0);

// ── Recent leads (last 7 days) ─────────────────────────────────
const weekAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000);
const recentLeads = leads
  .filter(l => l['Inquiry Date'] && new Date(l['Inquiry Date']) >= weekAgo)
  .map(l => `- ${l['Client Name'] || 'Unknown'} | ${l['Lead Status']} | $${l['Quote Amount'] || 0} | ${l['Lead Source'] || 'N/A'}`);

// ── Refused breakdown ──────────────────────────────────────────
const refused = leads.filter(l => l['Lead Status'] === 'Refused');
const refusalReasons = {};
refused.forEach(l => {
  const r = l['Refusal Reason'] || 'Unknown';
  refusalReasons[r] = (refusalReasons[r] || 0) + 1;
});

// ── Lead source breakdown ──────────────────────────────────────
const bySources = {};
leads.forEach(l => {
  const s = l['Lead Source'] || 'Unknown';
  bySources[s] = (bySources[s] || 0) + 1;
});

// ── All leads compact list (last 100 for context) ──────────────
const leadList = leads
  .slice(0, 100)
  .map(l => `${l['Client Name'] || '?'} | ${l['Lead Status']} | Quote: $${l['Quote Amount'] || 0} | Invoice: $${l['Final Invoice Amount'] || 0} | Source: ${l['Lead Source'] || 'N/A'} | Date: ${l['Inquiry Date'] ? l['Inquiry Date'].slice(0, 10) : 'N/A'}`)
  .join('\n');

// ── Build system prompt ────────────────────────────────────────
const systemPrompt = `You are a smart business assistant for Pearl View, an Australian window cleaning company. The owner will ask you questions via WhatsApp about their leads, revenue, and clients. Answer clearly and concisely.

LIVE CRM DATA (as of right now):

OVERALL STATS:
- Total leads: ${total}
- Total revenue collected (Job Done): $${totalRevenue.toLocaleString('en-AU', { minimumFractionDigits: 2 })}
- Total value quoted: $${totalQuoted.toLocaleString('en-AU', { minimumFractionDigits: 2 })}

STATUS BREAKDOWN:
${Object.entries(byStatus).map(([s, c]) => `- ${s}: ${c}`).join('\n')}

LEAD SOURCE BREAKDOWN:
${Object.entries(bySources).map(([s, c]) => `- ${s}: ${c}`).join('\n')}

REFUSAL REASONS:
${Object.entries(refusalReasons).length ? Object.entries(refusalReasons).map(([r, c]) => `- ${r}: ${c}`).join('\n') : '- None'}

RECENT LEADS (last 7 days):
${recentLeads.length ? recentLeads.join('\n') : '- No new leads this week'}

ALL LEADS (Name | Status | Quote | Invoice | Source | Date):
${leadList}

RULES:
- Use plain text only — no asterisks, no markdown, no bullet symbols. Just clean lines.
- Keep answers short unless the owner asks for a full report.
- Format money as AUD with $ sign.
- If asked something you cannot answer from the data, say so honestly.
- Do not make up data.`;

return [{ json: { systemPrompt, userMessage, senderPhone } }];

// Extract Claude's reply text
const response = $input.first().json;
const replyText = response.content?.[0]?.text || 'Sorry, I could not generate a response. Please try again.';
const senderPhone = $('Build AI Prompt').first().json.senderPhone;

return [{ json: { replyText, senderPhone } }];
